import type { JSX } from 'react';
import { useBimStore } from '../state/store';
import { WALL_LOCATION_LINE_ORDER, type WallLocationLine } from '../tools/toolGrammar';

const LOCATION_LINE_LABELS: Record<WallLocationLine, string> = {
  'wall-centerline': 'Wall Centerline',
  'finish-face-exterior': 'Finish Face: Exterior',
  'finish-face-interior': 'Finish Face: Interior',
  'core-centerline': 'Core Centerline',
  'core-face-exterior': 'Core Face: Exterior',
  'core-face-interior': 'Core Face: Interior',
};

const BAR_CLASS = 'flex items-center gap-4 border-b border-border bg-surface py-1 px-3 text-xs';

export function OptionsBar(): JSX.Element | null {
  const planTool = useBimStore((s) => s.planTool);
  const wallLocationLine = useBimStore((s) => s.wallLocationLine);
  const setWallLocationLine = useBimStore((s) => s.setWallLocationLine);
  const floorBoundaryOffsetMm = useBimStore((s) => s.floorBoundaryOffsetMm);
  const setFloorBoundaryOffsetMm = useBimStore((s) => s.setFloorBoundaryOffsetMm);
  const wallDrawHeightMm = useBimStore((s) => s.wallDrawHeightMm);
  const setWallDrawHeightMm = useBimStore((s) => s.setWallDrawHeightMm);

  if (planTool === 'wall') {
    return (
      <div data-testid="options-bar" className={BAR_CLASS}>
        <span className="text-muted">Location Line:</span>
        <select
          value={wallLocationLine}
          onChange={(e) => setWallLocationLine(e.target.value as WallLocationLine)}
          className="rounded border border-border bg-surface px-1.5 py-0.5 text-xs text-foreground"
          aria-label="Wall location line"
        >
          {WALL_LOCATION_LINE_ORDER.map((loc) => (
            <option key={loc} value={loc}>
              {LOCATION_LINE_LABELS[loc]}
            </option>
          ))}
        </select>
        <span className="text-muted opacity-60">Tab to cycle</span>
        <label className="flex items-center gap-2">
          <span className="text-muted">Height:</span>
          <input
            type="number"
            value={wallDrawHeightMm}
            step={100}
            min={100}
            onChange={(e) => setWallDrawHeightMm(Number(e.target.value))}
            className="w-20 rounded border border-border bg-surface px-1.5 py-0.5 text-xs text-foreground"
            aria-label="Wall height in mm"
            data-testid="options-bar-wall-height"
          />
          <span className="text-muted opacity-60">mm</span>
        </label>
      </div>
    );
  }

  if (planTool === 'floor') {
    return (
      <div data-testid="options-bar" className={BAR_CLASS}>
        <label className="flex items-center gap-2">
          <span className="text-muted">Boundary Offset:</span>
          <input
            type="number"
            value={floorBoundaryOffsetMm}
            onChange={(e) => setFloorBoundaryOffsetMm(Number(e.target.value))}
            className="w-20 rounded border border-border bg-surface px-1.5 py-0.5 text-xs text-foreground"
            aria-label="Floor boundary offset in mm"
          />
          <span className="text-muted opacity-60">mm</span>
        </label>
      </div>
    );
  }

  return null;
}

import { useState } from 'react';

import type { Element } from '@bim-ai/core';

export function LevelStack(props: {
  levels: Extract<Element, { kind: 'level' }>[];

  activeId: string;

  setActive(id: string): void;

  onElevationCommitted(levelId: string, elevationMm: number): void;

  onNameCommitted?: (levelId: string, name: string) => void;

  onCreatePlanView?: (levelId: string, levelName: string) => void;
}) {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [nameDraft, setNameDraft] = useState('');

  function commitEdit(levelId: string) {
    if (!editingId || editingId !== levelId) return;
    const trimmed = nameDraft.trim();
    if (trimmed && trimmed !== (props.levels.find((l) => l.id === levelId)?.name ?? '')) {
      props.onNameCommitted?.(levelId, trimmed);
    }
    setEditingId(null);
    setNameDraft('');
  }

  function cancelEdit() {
    setEditingId(null);
    setNameDraft('');
  }

  return (
    <div className="rounded border bg-surface p-2">
      <div className="text-[11px] font-semibold uppercase text-muted">Levels</div>

      <ul className="mt-2 space-y-1">
        {props.levels.map((lv) => (
          <li key={lv.id} className="flex flex-wrap items-center gap-2 text-xs">
            {editingId === lv.id ? (
              <input
                autoFocus
                type="text"
                data-testid={`level-name-input-${lv.id}`}
                value={nameDraft}
                className="rounded border border-border bg-background px-1 py-0.5 text-xs font-medium"
                onChange={(e) => setNameDraft(e.currentTarget.value)}
                onBlur={() => commitEdit(lv.id)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    commitEdit(lv.id);
                  }
                  if (e.key === 'Escape') {
                    e.preventDefault();
                    cancelEdit();
                  }
                }}
              />
            ) : (
              <button
                type="button"
                className={
                  'rounded px-2 py-1 font-medium ' +
                  (props.activeId === lv.id ? 'bg-accent/30' : 'hover:bg-accent/10')
                }
                onClick={() => props.setActive(lv.id)}
                onDoubleClick={
                  props.onNameCommitted
                    ? () => {
                        setEditingId(lv.id);
                        setNameDraft(lv.name);
                      }
                    : undefined
                }
                title={props.onNameCommitted ? 'Double-click to rename' : undefined}
              >
                {lv.name}
              </button>
            )}

            {props.onCreatePlanView && editingId !== lv.id && (
              <button
                type="button"
                data-testid={`level-create-view-${lv.id}`}
                title="Create floor plan view for this level"
                className="rounded px-1 py-0.5 text-[10px] text-muted hover:bg-accent/10 hover:text-foreground"
                onClick={() => props.onCreatePlanView!(lv.id, lv.name)}
              >
                +
              </button>
            )}

            <label className="flex items-center gap-1 text-[10px] text-muted">
              Elev (mm)
              <input
                defaultValue={String(lv.elevationMm)}
                className="w-24 rounded border border-border bg-background px-1 py-0.5 font-mono text-[11px]"
                key={`${lv.id}-${lv.elevationMm}`}
                type="number"
                onBlur={(e) => props.onElevationCommitted(lv.id, Number(e.currentTarget.value))}
              />
            </label>
          </li>
        ))}
      </ul>
    </div>
  );
}

import type { JSX } from 'react';
import { useMemo } from 'react';

import type { Element } from '@bim-ai/core';

import { BUILT_IN_FAMILIES } from '../families/familyCatalog';
import { LevelStack } from '../levels/LevelStack';
import { useBimStore } from '../state/store';
import { LeftRail } from './LeftRail';
import type { WorkspaceMode } from './TopBar';
import { buildBrowserSections } from './workspaceUtils';

export function WorkspaceLeftRail({
  onSemanticCommand,
  openTabFromElement,
  onModeChange,
  onOpenFamilyLibrary,
}: {
  onSemanticCommand: (cmd: Record<string, unknown>) => void | Promise<void>;
  openTabFromElement: (el: Element) => void;
  onModeChange: (mode: WorkspaceMode) => void;
  onOpenFamilyLibrary?: () => void;
}): JSX.Element {
  const elementsById = useBimStore((s) => s.elementsById);
  const activeLevelId = useBimStore((s) => s.activeLevelId);
  const setActiveLevelId = useBimStore((s) => s.setActiveLevelId);
  const selectedId = useBimStore((s) => s.selectedId);
  const select = useBimStore((s) => s.select);
  const setOrbitCameraFromViewpointMm = useBimStore((s) => s.setOrbitCameraFromViewpointMm);
  const setActiveViewpointId = useBimStore((s) => s.setActiveViewpointId);

  const browserSections = useMemo(() => buildBrowserSections(elementsById), [elementsById]);

  const activeFamilyTypeId = useMemo(() => {
    if (!selectedId) return undefined;
    const el = elementsById[selectedId];
    if (!el) return undefined;
    if (el.kind === 'door' || el.kind === 'window') return el.familyTypeId ?? undefined;
    return undefined;
  }, [selectedId, elementsById]);

  return (
    <div className="flex h-full flex-col overflow-hidden">
      {onOpenFamilyLibrary ? (
        <div className="shrink-0 border-b border-border p-2">
          <button
            type="button"
            onClick={onOpenFamilyLibrary}
            data-testid="left-rail-open-family-library"
            className="w-full rounded border border-border bg-surface-strong px-2 py-1 text-left text-xs hover:bg-accent-soft"
          >
            Families…
          </button>
        </div>
      ) : null}
      <div className="shrink-0 border-b border-border p-2">
        <LevelStack
          levels={(Object.values(elementsById) as Element[])
            .filter((e): e is Extract<Element, { kind: 'level' }> => e.kind === 'level')
            .sort((a, b) => a.elevationMm - b.elevationMm)}
          activeId={activeLevelId ?? ''}
          setActive={setActiveLevelId}
          onElevationCommitted={(levelId, elevationMm) =>
            void onSemanticCommand({ type: 'moveLevelElevation', levelId, elevationMm })
          }
          onNameCommitted={(levelId, name) =>
            void onSemanticCommand({
              type: 'updateElementProperty',
              elementId: levelId,
              key: 'name',
              value: name,
            })
          }
          onCreatePlanView={(levelId, levelName) =>
            void onSemanticCommand({
              type: 'upsertPlanView',
              id: crypto.randomUUID(),
              name: `${levelName} — Plan`,
              levelId,
              discipline: 'architecture',
            })
          }
        />
      </div>
      <div className="min-h-0 flex-1 overflow-y-auto">
        <LeftRail
          sections={browserSections}
          activeRowId={activeFamilyTypeId ?? activeLevelId}
          onRowActivate={(id) => {
            if (id === 'new-wall-type') {
              void onSemanticCommand({
                type: 'upsertWallType',
                id: crypto.randomUUID(),
                name: 'New Wall Type',
                basisLine: 'center',
                layers: [{ thicknessMm: 200, function: 'structure', materialKey: '' }],
              });
              return;
            }
            if (id === 'new-floor-type') {
              void onSemanticCommand({
                type: 'upsertFloorType',
                id: crypto.randomUUID(),
                name: 'New Floor Type',
                layers: [{ thicknessMm: 200, function: 'structure', materialKey: '' }],
              });
              return;
            }
            if (id === 'new-roof-type') {
              void onSemanticCommand({
                type: 'upsertRoofType',
                id: crypto.randomUUID(),
                name: 'New Roof Type',
                layers: [{ thicknessMm: 200, function: 'structure', materialKey: '' }],
              });
              return;
            }
            const pickedType = BUILT_IN_FAMILIES.flatMap((f) => f.defaultTypes).find(
              (t) => t.id === id,
            );
            if (pickedType) {
              if (selectedId) {
                const selEl = elementsById[selectedId];
                if (selEl && selEl.kind === pickedType.discipline) {
                  void onSemanticCommand({
                    type: 'updateElementProperty',
                    elementId: selectedId,
                    key: 'familyTypeId',
                    value: id,
                  });
                }
              }
              return;
            }
            const el = elementsById[id];
            if (!el) {
              const isLevel = browserSections
                .find((s) => s.id === 'project')
                ?.rows.find((r) => r.id === 'levels')
                ?.children?.some((c) => c.id === id);
              if (isLevel) setActiveLevelId(id);
              return;
            }
            if (el.kind === 'level') {
              setActiveLevelId(id);
              openTabFromElement(el);
              onModeChange('plan');
              return;
            }
            if (el.kind === 'plan_view') {
              openTabFromElement(el);
              onModeChange('plan');
              select(id);
              return;
            }
            if (el.kind === 'viewpoint') {
              openTabFromElement(el);
              onModeChange('3d');
              select(id);
              if (el.mode === 'orbit_3d' && el.camera) {
                setOrbitCameraFromViewpointMm({
                  position: el.camera.position,
                  target: el.camera.target,
                  up: el.camera.up,
                });
                setActiveViewpointId(el.id);
              }
              return;
            }
            if (el.kind === 'section_cut') {
              openTabFromElement(el);
              onModeChange('section');
              select(id);
              return;
            }
            if (el.kind === 'sheet') {
              openTabFromElement(el);
              onModeChange('sheet');
              select(id);
              return;
            }
            if (el.kind === 'schedule') {
              openTabFromElement(el);
              onModeChange('schedule');
              select(id);
              return;
            }
            select(id);
          }}
        />
      </div>
    </div>
  );
}

import { type JSX } from 'react';

import {
  TAG_FAMILIES,
  TOOL_CAPABILITIES,
  type TagFamily,
  type ToolGrammarModifiers,
  WALL_LOCATION_LINE_ORDER,
  type WallLocationLine,
} from './toolGrammar';
import type { ToolId } from './toolRegistry';

/**
 * EDT-06 — Options Bar.
 *
 * Mimics Revit's Options Bar: appears when a tool is active, exposes the
 * Chain / Multiple / Tag-on-Place / Numeric-input modifiers plus
 * tool-specific options (e.g. Wall location-line). The component itself
 * is presentational; toggle handlers and modifier state are owned by
 * the canvas / workspace shell.
 */

export interface OptionsBarProps {
  activeTool: ToolId | null;
  modifiers: ToolGrammarModifiers;
  onModifiersChange: (next: ToolGrammarModifiers) => void;
  /** Wall-tool only. Pass `undefined` for non-wall tools. */
  wallLocationLine?: WallLocationLine;
  onWallLocationLineChange?: (next: WallLocationLine) => void;
}

const WALL_LOCATION_LABELS: Record<WallLocationLine, string> = {
  'wall-centerline': 'Wall centerline',
  'finish-face-exterior': 'Finish face: ext.',
  'finish-face-interior': 'Finish face: int.',
  'core-centerline': 'Core centerline',
  'core-face-exterior': 'Core face: ext.',
  'core-face-interior': 'Core face: int.',
};

export function OptionsBar({
  activeTool,
  modifiers,
  onModifiersChange,
  wallLocationLine,
  onWallLocationLineChange,
}: OptionsBarProps): JSX.Element | null {
  if (!activeTool || activeTool === 'select') return null;
  const caps = TOOL_CAPABILITIES[activeTool];
  if (!caps) return null;
  const showAny =
    caps.chainable ||
    caps.multipleable ||
    caps.tagOnPlace ||
    caps.numericInput ||
    activeTool === 'wall';
  if (!showAny) return null;

  return (
    <div
      role="toolbar"
      aria-label="Tool options"
      data-testid="options-bar"
      style={{
        position: 'absolute',
        top: 8,
        left: '50%',
        transform: 'translateX(-50%)',
        display: 'flex',
        alignItems: 'center',
        gap: 12,
        padding: '6px 12px',
        borderRadius: 6,
        background: 'var(--color-surface, #1b2433)',
        color: 'var(--color-on-surface, #e6edf6)',
        boxShadow: '0 2px 8px rgba(0,0,0,0.35)',
        font: 'var(--text-sm, 12px system-ui)',
        zIndex: 30,
      }}
    >
      {caps.chainable && (
        <label style={{ display: 'flex', gap: 4, alignItems: 'center' }}>
          <input
            type="checkbox"
            data-testid="options-bar-chain"
            checked={modifiers.chainable}
            onChange={(ev) =>
              onModifiersChange({ ...modifiers, chainable: ev.currentTarget.checked })
            }
          />
          <span>Chain</span>
        </label>
      )}
      {caps.multipleable && (
        <label style={{ display: 'flex', gap: 4, alignItems: 'center' }}>
          <input
            type="checkbox"
            data-testid="options-bar-multiple"
            checked={modifiers.multipleable}
            onChange={(ev) =>
              onModifiersChange({ ...modifiers, multipleable: ev.currentTarget.checked })
            }
          />
          <span>Multiple</span>
        </label>
      )}
      {caps.tagOnPlace && (
        <label style={{ display: 'flex', gap: 4, alignItems: 'center' }}>
          <input
            type="checkbox"
            data-testid="options-bar-tag-on-place"
            checked={modifiers.tagOnPlace.enabled}
            onChange={(ev) =>
              onModifiersChange({
                ...modifiers,
                tagOnPlace: { ...modifiers.tagOnPlace, enabled: ev.currentTarget.checked },
              })
            }
          />
          <span>Tag on Place</span>
          {modifiers.tagOnPlace.enabled && (
            <select
              data-testid="options-bar-tag-family"
              value={modifiers.tagOnPlace.tagFamilyId ?? ''}
              onChange={(ev) =>
                onModifiersChange({
                  ...modifiers,
                  tagOnPlace: {
                    ...modifiers.tagOnPlace,
                    tagFamilyId: ev.currentTarget.value as TagFamily | '',
                  },
                })
              }
              style={{ marginLeft: 4 }}
            >
              <option value="">(default)</option>
              {TAG_FAMILIES.map((f) => (
                <option key={f.id} value={f.id}>
                  {f.label}
                </option>
              ))}
            </select>
          )}
        </label>
      )}
      {caps.numericInput && (
        <span data-testid="options-bar-numeric-hint" style={{ opacity: 0.7, fontStyle: 'italic' }}>
          Type a digit while drawing for exact length
        </span>
      )}
      {activeTool === 'wall' && wallLocationLine && onWallLocationLineChange && (
        <label style={{ display: 'flex', gap: 4, alignItems: 'center' }}>
          <span>Location line:</span>
          <select
            data-testid="options-bar-wall-location-line"
            value={wallLocationLine}
            onChange={(ev) => onWallLocationLineChange(ev.currentTarget.value as WallLocationLine)}
          >
            {WALL_LOCATION_LINE_ORDER.map((ll) => (
              <option key={ll} value={ll}>
                {WALL_LOCATION_LABELS[ll]}
              </option>
            ))}
          </select>
        </label>
      )}
      {activeTool === 'wall' && (
        <label style={{ display: 'flex', gap: 4, alignItems: 'center' }}>
          <span>Offset (mm):</span>
          <input
            type="number"
            data-testid="options-bar-wall-offset"
            value={modifiers.wallDrawOffsetMm}
            step={50}
            onChange={(ev) =>
              onModifiersChange({ ...modifiers, wallDrawOffsetMm: Number(ev.currentTarget.value) })
            }
            style={{ width: 64 }}
          />
        </label>
      )}
      {activeTool === 'wall' && (
        <label style={{ display: 'flex', gap: 4, alignItems: 'center' }}>
          <input
            type="checkbox"
            data-testid="options-bar-wall-radius-toggle"
            checked={modifiers.wallDrawRadiusMm !== null}
            onChange={(ev) =>
              onModifiersChange({
                ...modifiers,
                wallDrawRadiusMm: ev.currentTarget.checked ? 500 : null,
